    expect(movedTemplate).toEqual(expect.objectContaining({ color: "#f97316", groupLabel: "Moved Hazards", groupId: "moved-hazards" }));
    expect(movedTemplate.points).toEqual([{ x: 550, y: 400 }, { x: 650, y: 400 }]);
