  it("uses configured session TTL days for new bearer sessions", async () => {
    const previousEnv = snapshotEnv(["OTTE_SESSION_TTL_DAYS"]);
    process.env.OTTE_SESSION_TTL_DAYS = "2";

    const app = await buildApp({ store: new MemoryStateStore() });
    try {
      const before = Date.now();
      const login = await app.inject({
        method: "POST",
        url: "/api/v1/auth/login",
        payload: { email: "player@example.test" }
      });
      const after = Date.now();
      expect(login.statusCode).toBe(200);
      const expiresAt = Date.parse(login.json().session.expiresAt);
      expect(expiresAt).toBeGreaterThanOrEqual(before + 2 * 24 * 60 * 60 * 1000 - 1000);
      expect(expiresAt).toBeLessThanOrEqual(after + 2 * 24 * 60 * 60 * 1000 + 1000);
    } finally {
      await app.close();
      restoreEnv(previousEnv);
    }
  });

