  it("supports bright and dim token vision zones with validation and diagnostics", async () => {
    const previousEnv = snapshotEnv(["OTTE_ADMIN_USER_IDS"]);
    process.env.OTTE_ADMIN_USER_IDS = "usr_demo_gm";
    const store = new MemoryStateStore();
    const scene = store.state.scenes.find((item) => item.id === "scn_vault_entry")!;
    scene.fog = [];
    scene.walls = [];
    const valen = store.state.tokens.find((item) => item.id === "tok_valen")!;
    valen.visionRadius = 240;
    valen.brightVisionRadius = 80;
    valen.dimVisionRadius = 240;
    const app = await buildApp({ store });
    try {
      const adminLogin = await app.inject({
        method: "POST",
        url: "/api/v1/auth/login",
        payload: { email: "gm@example.test" }
      });
      const adminHeaders = { authorization: `Bearer ${adminLogin.json().token}` };
      const playerHeaders = { "x-user-id": "usr_demo_player" };

      const invalidCreate = await app.inject({
        method: "POST",
        url: "/api/v1/scenes/scn_vault_entry/tokens",
        headers: adminHeaders,
        payload: { name: "Bad Vision", visionRadius: 120, brightVisionRadius: 140, dimVisionRadius: 120 }
      });
      expect(invalidCreate.statusCode).toBe(400);

      const invalidPatch = await app.inject({
        method: "PATCH",
        url: "/api/v1/tokens/tok_valen",
        headers: adminHeaders,
        payload: { brightVisionRadius: 260 }
      });
      expect(invalidPatch.statusCode).toBe(400);

      const patched = await app.inject({
        method: "PATCH",
        url: "/api/v1/tokens/tok_valen",
        headers: adminHeaders,
        payload: { brightVisionRadius: 90, dimVisionRadius: 260, visionRadius: 260 }
      });
      expect(patched.statusCode).toBe(200);
      expect(patched.json()).toEqual(expect.objectContaining({ brightVisionRadius: 90, dimVisionRadius: 260, visionRadius: 260 }));

      scene.fog = [{ id: "fog_center", x: 500, y: 380, radius: 320, hidden: false }];
      const vision = await app.inject({
        method: "GET",
        url: "/api/v1/scenes/scn_vault_entry/vision",
        headers: playerHeaders
      });
      expect(vision.statusCode).toBe(200);
      expect(vision.json().polygons).toEqual(
        expect.arrayContaining([
          expect.objectContaining({ source: "token", sourceId: "tok_valen", lightLevel: "dim", radius: 260 }),
          expect.objectContaining({ source: "token", sourceId: "tok_valen", lightLevel: "bright", radius: 90 })
        ])
      );

      const dimSample = await app.inject({
        method: "GET",
        url: "/api/v1/scenes/scn_vault_entry/vision/sample?x=500&y=375",
        headers: playerHeaders
      });
      expect(dimSample.statusCode).toBe(200);
      expect(dimSample.json().revealedBy).toEqual(expect.arrayContaining([expect.objectContaining({ source: "token", sourceId: "tok_valen", lightLevel: "dim", radius: 260 })]));
      expect(dimSample.json().revealedBy).not.toEqual(expect.arrayContaining([expect.objectContaining({ source: "token", sourceId: "tok_valen", lightLevel: "bright" })]));

      const brightSample = await app.inject({
        method: "GET",
        url: "/api/v1/scenes/scn_vault_entry/vision/sample?x=360&y=375",
        headers: playerHeaders
      });
      expect(brightSample.statusCode).toBe(200);
      expect(brightSample.json().revealedBy).toEqual(expect.arrayContaining([expect.objectContaining({ source: "token", sourceId: "tok_valen", lightLevel: "bright", radius: 90 })]));

      const operations = await app.inject({
        method: "GET",
        url: "/api/v1/admin/rendering/operations",
        headers: adminHeaders
      });
      expect(operations.statusCode).toBe(200);
      expect(operations.json().featureCoverage).toEqual(
        expect.objectContaining({
          scenesWithDualZoneTokenVisionCount: 1,
          dualZoneTokenVisionCoverageRate: 1
        })
      );
      expect(operations.json().featureCoverage.requiredFeatures).toEqual(expect.arrayContaining([expect.objectContaining({ code: "dual_zone_token_vision", present: true })]));
      expect(operations.json().featureCoverage.missingRequiredFeatureCodes).not.toContain("dual_zone_token_vision");
    } finally {
      await app.close();
      restoreEnv(previousEnv);
    }
  });

