  it("returns Codex app-server OAuth login details when the agent needs ChatGPT auth", async () => {
    class AuthRequiredProvider implements AiProvider {
      id = "codex-app-server";
      label = "Codex App Server";

      async *stream(_input: AiProviderRequest): AsyncIterable<AiProviderEvent> {
        const error = new Error("Codex app-server ChatGPT sign-in is required.") as Error & {
          code: "codex_auth_required";
          login: { type: "chatgpt"; loginId: string; authUrl: string };
        };
        error.code = "codex_auth_required";
        error.login = {
          type: "chatgpt",
          loginId: "login_test",
          authUrl: "https://chatgpt.test/oauth"
        };
        throw error;
      }
    }

    const store = new MemoryStateStore();
    const app = await buildApp({ store, aiProvider: new AuthRequiredProvider() });
    const response = await app.inject({
      method: "POST",
      url: "/api/v1/campaigns/camp_demo/ai/threads",
      headers: authHeaders,
      payload: {
        prompt: "Move Valen with the agent.",
        surface: "agent_panel"
      }
    });

    expect(response.statusCode).toBe(428);
    expect(response.json()).toMatchObject({
      error: "codex_auth_required",
      message: "Codex app-server ChatGPT sign-in is required.",
      codexAuth: {
        type: "chatgpt",
        loginId: "login_test",
        authUrl: "https://chatgpt.test/oauth"
      },
      thread: {
        provider: "codex-app-server",
        status: "failed",
        providerError: "Codex app-server ChatGPT sign-in is required."
      }
    });
    expect(store.state.aiThreads.at(-1)).toMatchObject({ status: "failed", providerError: "Codex app-server ChatGPT sign-in is required." });
    await app.close();
  });

  it("defaults agent threads to Codex app-server instead of local echo", async () => {
    const previousEnv = snapshotEnv(["OTTE_AI_PROVIDER", "OTTE_CODEX_APP_SERVER_URL", "OTTE_CODEX_APP_SERVER_AUTOSTART", "OTTE_AI_PROVIDER_TIMEOUT_MS", "OTTE_AI_PROVIDER_RETRY_ATTEMPTS"]);
    delete process.env.OTTE_AI_PROVIDER;
    process.env.OTTE_CODEX_APP_SERVER_URL = "ws://127.0.0.1:1";
    process.env.OTTE_CODEX_APP_SERVER_AUTOSTART = "false";
    process.env.OTTE_AI_PROVIDER_TIMEOUT_MS = "25";
    process.env.OTTE_AI_PROVIDER_RETRY_ATTEMPTS = "0";
    const app = await buildApp({ store: new MemoryStateStore() });

    try {
      const response = await app.inject({
        method: "POST",
        url: "/api/v1/campaigns/camp_demo/ai/threads",
        headers: authHeaders,
        payload: {
          prompt: "Use the real agent provider.",
          surface: "agent_panel"
        }
      });
      const bodyText = response.body;

      expect(response.statusCode).toBe(502);
      expect(response.json()).toMatchObject({
        error: "ai_provider_failed",
        thread: {
          provider: "codex-app-server",
          status: "failed"
        }
      });
      expect(bodyText).toContain("Codex app-server");
      expect(bodyText).not.toContain("Draft response");
      expect(bodyText).not.toContain("local-echo");
    } finally {
      await app.close();
      restoreEnv(previousEnv);
    }
  });

