  it("flags invalid asset runtime numeric env values without exposing raw values", async () => {
    const previousEnv = snapshotEnv([
      "NODE_ENV",
      "OTTE_ADMIN_USER_IDS",
      "OTTE_ASSET_CDN_BASE_URL",
      "OTTE_ASSET_CDN_PURGE_WEBHOOK_URL",
      "OTTE_ASSET_QUOTA_BYTES",
      "OTTE_ASSET_RETENTION_DAYS",
      "OTTE_ASSET_URL_SIGNING_SECRET",
      "OTTE_ASSET_URL_TTL_SECONDS",
      "OTTE_ASSET_URL_MAX_TTL_SECONDS",
      "OTTE_ASSET_CDN_PURGE_TIMEOUT_MS",
      "OTTE_ASSET_TRUST_TIMEOUT_MS",
      "OTTE_ASSET_CLEANUP_GRACE_DAYS",
      "OTTE_ASSET_CLEANUP_INTERVAL_SECONDS"
    ]);
    process.env.NODE_ENV = "test";
    process.env.OTTE_ADMIN_USER_IDS = "usr_demo_gm";
    delete process.env.OTTE_ASSET_CDN_BASE_URL;
    delete process.env.OTTE_ASSET_CDN_PURGE_WEBHOOK_URL;
    delete process.env.OTTE_ASSET_URL_SIGNING_SECRET;
    process.env.OTTE_ASSET_QUOTA_BYTES = "not-bytes";
    process.env.OTTE_ASSET_RETENTION_DAYS = "-1";
    process.env.OTTE_ASSET_URL_TTL_SECONDS = "bad-ttl";
    process.env.OTTE_ASSET_URL_MAX_TTL_SECONDS = "-10";
    process.env.OTTE_ASSET_CDN_PURGE_TIMEOUT_MS = "not-timeout";
    process.env.OTTE_ASSET_TRUST_TIMEOUT_MS = "-5";
    process.env.OTTE_ASSET_CLEANUP_GRACE_DAYS = "bad-grace";
    process.env.OTTE_ASSET_CLEANUP_INTERVAL_SECONDS = "-1";

    const store = new MemoryStateStore();
    const app = await buildApp({ store });
    try {
      const login = await loginDemoUser(app, store);
      const invalidConfig = [
        "OTTE_ASSET_QUOTA_BYTES",
        "OTTE_ASSET_RETENTION_DAYS",
        "OTTE_ASSET_URL_TTL_SECONDS",
        "OTTE_ASSET_URL_MAX_TTL_SECONDS",
        "OTTE_ASSET_CDN_PURGE_TIMEOUT_MS",
        "OTTE_ASSET_TRUST_TIMEOUT_MS",
        "OTTE_ASSET_CLEANUP_GRACE_DAYS",
        "OTTE_ASSET_CLEANUP_INTERVAL_SECONDS"
      ];
      const storage = await app.inject({
        method: "GET",
        url: "/api/v1/admin/assets/storage",
        headers: { authorization: `Bearer ${login.json().token}` }
      });
      expect(storage.statusCode).toBe(200);
      expect(storage.json()).toMatchObject({
        runtime: { invalidConfig },
        operations: {
          actionRequired: true,
          actionReasons: ["delivery_configuration_warnings"],
          delivery: {
            warnings: [
              expect.objectContaining({
                code: "asset_runtime_config_invalid",
                severity: "warning",
                env: invalidConfig
              })
            ]
          },
          remediationQueue: [
            expect.objectContaining({
              code: "fix_asset_delivery_configuration",
              severity: "warning",
              action: expect.stringContaining("Configure signing secrets"),
              affectedCount: 1,
              samples: [
                expect.objectContaining({
                  code: "asset_runtime_config_invalid",
                  severity: "warning"
                })
              ]
            })
          ]
        }
      });
      const body = JSON.stringify(storage.json());
      expect(body).not.toContain("not-bytes");
      expect(body).not.toContain("bad-ttl");
      expect(body).not.toContain("not-timeout");
      expect(body).not.toContain("bad-grace");
    } finally {
      await app.close();
      restoreEnv(previousEnv);
    }
  });

