    const asset: MapAsset = createTimestamped("asset", {
      campaignId: "camp_demo",
      name: "Migration Source.png",
      url: "",
      mimeType: "image/png",
      sizeBytes: bytes.length,
      lifecycle: { status: "active" }
    });
